      'str(x)': 'Convert x to string representation',
      'repr(s)': 'Unambiguous representation with quotes',
      'ord(c)': 'Unicode point: ord("A")=65',
      'chr(n)': 'Char from point: chr(65)="A"',
      'format(val, spec)': 'format(255, "#x")="0xff"',
